export async function searchTescoProducts(query) {
  const url = `https://tesco8.p.rapidapi.com/product-search-by-keyword?query=${encodeURIComponent(query)}`;

  try {
    const res = await fetch(url, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
        'x-rapidapi-host': 'tesco8.p.rapidapi.com',
        'x-rapidapi-key': process.env.REACT_APP_RAPIDAPI_KEY
      }
    });

    console.log('Tesco status:', res.status);
    console.log('Searching for:', query);
    console.log('API Key being used:', process.env.REACT_APP_RAPIDAPI_KEY ? 'Key exists' : 'KEY IS UNDEFINED');

    const data = await res.json();
    console.log('Tesco raw response:', JSON.stringify(data).slice(0, 300));

    const products = data?.data?.products || [];
    console.log('Products found:', products.length);

    return products
      .filter(p => p.isForSale)
      .slice(0, 3)
      .map(p => ({
        id: p.id,
        label: p.title,
        brand: p.brand,
        qty: p.title,
        price: p.price.price,
        image: p.imageUrl,
        clubcardPrice: p.promotions?.[0]?.description || null
      }));
  } catch (e) {
    console.error('Tesco fetch error:', e);
    return [];
  }
}
